+
+/** Type checker visitor for binary operators. */
+class BinOpTypeChecker implements BinOpVisitor<Type> {
+  private Type t1, t2;
+  BinOpTypeChecker(Type t1, Type t2) { this.t1 = t1; this.t2 = t2; }
+
+  private void requireInt(Type t, String op) {
+    if (!t.equals(IntType.ONLY))
+      throw new TypeException("Operator '" + op + "' requires int, got " + t);
+  }
+
+  private void requireBool(Type t, String op) {
+    if (!t.equals(BoolType.ONLY))
+      throw new TypeException("Operator '" + op + "' requires bool, got " + t);
+  }
+
+  public Type forBinOpPlus()           { requireInt(t1, "+"); requireInt(t2, "+"); return IntType.ONLY; }
+  public Type forBinOpMinus()          { requireInt(t1, "-"); requireInt(t2, "-"); return IntType.ONLY; }
+  public Type forOpTimes()             { requireInt(t1, "*"); requireInt(t2, "*"); return IntType.ONLY; }
+  public Type forOpDivide()            { requireInt(t1, "/"); requireInt(t2, "/"); return IntType.ONLY; }
+  public Type forOpLessThan()          { requireInt(t1, "<"); requireInt(t2, "<"); return BoolType.ONLY; }
+  public Type forOpGreaterThan()       { requireInt(t1, ">"); requireInt(t2, ">"); return BoolType.ONLY; }
+  public Type forOpLessThanEquals()    { requireInt(t1, "<="); requireInt(t2, "<="); return BoolType.ONLY; }
+  public Type forOpGreaterThanEquals() { requireInt(t1, ">="); requireInt(t2, ">="); return BoolType.ONLY; }
+  public Type forOpAnd()               { requireBool(t1, "&"); requireBool(t2, "&"); return BoolType.ONLY; }
+  public Type forOpOr()                { requireBool(t1, "|"); requireBool(t2, "|"); return BoolType.ONLY; }
+
+  public Type forOpEquals() {
+    if (!t1.equals(t2))
+      throw new TypeException("'=' requires operands of the same type, got " + t1 + " and " + t2);
+    return BoolType.ONLY;
+  }
+
+  public Type forOpNotEquals() {
+    if (!t1.equals(t2))
+      throw new TypeException("'!=' requires operands of the same type, got " + t1 + " and " + t2);
+    return BoolType.ONLY;
+  }
+
+  public Type forOpGets() {
+    /* '<- : ref 'a, 'a -> unit' */
+    if (!(t1 instanceof RefType))
+      throw new TypeException("'<-' requires a ref type on the left, got " + t1);
+    RefType rt = (RefType) t1;
+    if (!t2.equals(rt.elemType()))
+      throw new TypeException("'<-' type mismatch: ref element type is " + rt.elemType() + " but right side has type " + t2);
+    return UnitType.ONLY;
+  }
+}
